import React, { useState } from "react";
import { useMsal } from "@azure/msal-react";
import { loginRequest } from "./authConfig";

const App = () => {
    const { instance, accounts } = useMsal();
    const [data, setData] = useState([]);

    const handleLogin = async () => {
        try {
            const response = await instance.loginPopup(loginRequest);
            console.log("Giri� ba�ar�l�:", response);
        } catch (err) {
            console.error("Giri� hatas�:", err);
        }
    };

    const getExcelData = async () => {
        const account = accounts[0];
        const response = await instance.acquireTokenSilent({
            ...loginRequest,
            account,
        });

        const token = response.accessToken;

        const res = await fetch(
            "https://graph.microsoft.com/v1.0/me/drive/root:/TEDAR�K_PERFORMANS_RAPORU.xlsx:/workbook/worksheets",
            {
                headers: {
                    Authorization: `Bearer ${token}`,
                },
            }
        );

        const json = await res.json();
        console.log("Excel sayfalar�:", json);
        setData(json.value);
    };

    return (
        <div style={{ padding: 20 }}>
            <button onClick={handleLogin}>Microsoft ile Giri� Yap</button>
            <button onClick={getExcelData}>Veri �ek</button>

            <ul>
                {data.map((sheet, i) => (
                    <li key={i}>{sheet.name}</li>
                ))}
            </ul>
        </div>
    );
};

export default App;
